-- =============================================================================
-- Тест "Какие игры ты играешь?" для программы "Игры, в которые играют люди"
-- На основе Транзактного анализа Эрика Берна
-- 25 вопросов, 5 шкал, 5-балльная шкала Ликерта
-- ЦА: оба пола, гендерно-нейтральные формулировки
-- =============================================================================

-- 1. Вставляем тест-конфиг
INSERT INTO test_configs (
  program_id,
  slug,
  title,
  short_title,
  description,
  questions,
  scales,
  scoring,
  ui_config,
  interpretation_prompt,
  mini_analysis_prompt_template,
  is_active
) VALUES (
  (SELECT id FROM programs WHERE slug = 'games-people-play'),

  -- slug
  'gpp-test',

  -- title
  'Какие игры ты играешь?',

  -- short_title
  'Игры',

  -- description
  'Тест по книге «Игры, в которые играют люди» Эрика Берна. Покажет, какие привычные сценарии влияют на твои отношения, и с чего начать их менять.',

  -- questions (25 вопросов: 5 шкал × 5 вопросов, 3 direct + 2 reverse каждая)
  '[
    {"q":1,  "scale":"ta_game_tendency",  "type":"direct",  "text":"В конфликтах с близкими я замечаю, что разговор идёт по одному и тому же сценарию"},
    {"q":2,  "scale":"ta_game_tendency",  "type":"direct",  "text":"Бывает, что я провоцирую определённую реакцию у собеседника, хотя на словах хочу другого"},
    {"q":3,  "scale":"ta_game_tendency",  "type":"direct",  "text":"После ссоры я чувствую, что мог(ла) бы предсказать, чем всё закончится"},
    {"q":4,  "scale":"ta_game_tendency",  "type":"reverse", "text":"В сложных разговорах я говорю прямо о том, что мне нужно"},
    {"q":5,  "scale":"ta_game_tendency",  "type":"reverse", "text":"Когда возникает напряжение в общении, я обычно замечаю это и могу остановиться"},

    {"q":6,  "scale":"ta_ego_imbalance",  "type":"direct",  "text":"Я часто чувствую себя ответственным(-ой) за эмоции других людей"},
    {"q":7,  "scale":"ta_ego_imbalance",  "type":"direct",  "text":"В стрессе я реагирую не как взрослый человек — либо поучаю, либо обижаюсь"},
    {"q":8,  "scale":"ta_ego_imbalance",  "type":"direct",  "text":"Мне сложно просто обсудить проблему без того чтобы кто-то оказался виноват"},
    {"q":9,  "scale":"ta_ego_imbalance",  "type":"reverse", "text":"В большинстве ситуаций я могу спокойно оценить, что происходит, прежде чем реагировать"},
    {"q":10, "scale":"ta_ego_imbalance",  "type":"reverse", "text":"Я легко переключаюсь между серьёзностью и лёгкостью в зависимости от ситуации"},

    {"q":11, "scale":"ta_script_power",   "type":"direct",  "text":"Иногда мне кажется, что моя жизнь идёт по заранее написанному плану, который я не выбирал(а)"},
    {"q":12, "scale":"ta_script_power",   "type":"direct",  "text":"Я замечаю, что повторяю паттерны поведения своих родителей, даже если не хочу этого"},
    {"q":13, "scale":"ta_script_power",   "type":"direct",  "text":"В важных решениях я часто слышу внутренний голос: «таким, как ты, это не дано»"},
    {"q":14, "scale":"ta_script_power",   "type":"reverse", "text":"Я чувствую, что свободно выбираю, как строить свою жизнь"},
    {"q":15, "scale":"ta_script_power",   "type":"reverse", "text":"Мои жизненные решения основаны на моих реальных желаниях, а не на ожиданиях семьи"},

    {"q":16, "scale":"ta_stroke_deficit", "type":"direct",  "text":"Мне сложно принимать комплименты — я отшучиваюсь или обесцениваю их"},
    {"q":17, "scale":"ta_stroke_deficit", "type":"direct",  "text":"Я редко прошу о поддержке или внимании, даже когда нуждаюсь в этом"},
    {"q":18, "scale":"ta_stroke_deficit", "type":"direct",  "text":"Когда мне говорят что-то тёплое, я чувствую неловкость или недоверие"},
    {"q":19, "scale":"ta_stroke_deficit", "type":"reverse", "text":"Я легко говорю близким, что ценю их и они мне дороги"},
    {"q":20, "scale":"ta_stroke_deficit", "type":"reverse", "text":"Когда я хорошо справляюсь с чем-то, я могу порадоваться за себя без чувства неловкости"},

    {"q":21, "scale":"ta_drama_roles",    "type":"direct",  "text":"В конфликтах я часто чувствую себя жертвой обстоятельств или чужих решений"},
    {"q":22, "scale":"ta_drama_roles",    "type":"direct",  "text":"Когда кто-то из близких в беде, я бросаюсь спасать, даже если меня не просили"},
    {"q":23, "scale":"ta_drama_roles",    "type":"direct",  "text":"Я замечаю, что могу быстро переключиться от желания помочь к раздражению на того же человека"},
    {"q":24, "scale":"ta_drama_roles",    "type":"reverse", "text":"В конфликте я могу поддержать другого, не беря на себя ответственность за его проблему"},
    {"q":25, "scale":"ta_drama_roles",    "type":"reverse", "text":"Когда кто-то жалуется, я спокойно выслушиваю, не пытаясь немедленно всё исправить"}
  ]'::jsonb,

  -- scales
  '[
    {"key":"ta_game_tendency",  "name":"Склонность к играм",          "order":1, "exercises":[], "radar_label":["Склонность","к играм"]},
    {"key":"ta_ego_imbalance",  "name":"Дисбаланс эго-состояний",     "order":2, "exercises":[], "radar_label":["Дисбаланс","эго-состояний"]},
    {"key":"ta_script_power",   "name":"Власть сценария",             "order":3, "exercises":[], "radar_label":["Власть","сценария"]},
    {"key":"ta_stroke_deficit", "name":"Дефицит поглаживаний",        "order":4, "exercises":[], "radar_label":["Дефицит","поглаживаний"]},
    {"key":"ta_drama_roles",    "name":"Роли в драматреугольнике",    "order":5, "exercises":[], "radar_label":["Роли в драма-","треугольнике"]}
  ]'::jsonb,

  -- scoring
  '{
    "answer_range": [1, 5],
    "score_direction": "lower_is_better",
    "level_thresholds": [25, 50, 75],
    "level_labels": ["Низкий", "Умеренный", "Выраженный", "Высокий"]
  }'::jsonb,

  -- ui_config
  '{
    "questions_per_block": 5,
    "auth_wall_question": 19,
    "welcome_title": "Какие игры<br /><span>ты играешь?</span>",
    "welcome_subtitle": "Тест по книге «Игры, в которые играют люди» Эрика Берна",
    "welcome_description": "Это не клинический тест — это карта. Она покажет, какие привычные сценарии влияют на твои отношения, и с чего начать их менять.",
    "welcome_badge": "Транзактный анализ",
    "welcome_stats": [
      {"num": "25", "label": "вопросов"},
      {"num": "5", "label": "шкал"},
      {"num": "~5", "label": "минут"}
    ],
    "block_insights": [
      "Первые паттерны видны. Игры — это не злой умысел, а привычные сценарии. Берн говорил: осознание — первый шаг к свободе.",
      "Эго-состояния — это голоса внутри нас: Родитель, Взрослый, Ребёнок. Кто из них чаще берёт руль?",
